    [TestMethod]
    public void GenerateSlug_SimpleTwoWordTitle_ReturnsHyphenatedLowercase()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StripsNonAlphanumeric()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_TrimsCleanly()
    {
        var result = _formatter.GenerateSlug("  Padded Title  ");

        Assert.AreEqual("padded-title", result);
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("--Leading Dashes");

        Assert.IsFalse(result.StartsWith('-'));
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_DoesNotEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("Trailing Dashes--");

        Assert.IsFalse(result.EndsWith('-'));
    }

